if (typeof ErrorUtils !== 'undefined') {
  const _prevHandler = ErrorUtils.getGlobalHandler ? ErrorUtils.getGlobalHandler() : null;
  ErrorUtils.setGlobalHandler(function (error, isFatal) {
    try {
      Alert.alert('Erreur application', String(isFatal ? 'Fatale' : 'Non fatale') + ' : ' + String(error && error.message));
    } catch (e) {}
    if (_prevHandler) _prevHandler(error, isFatal);
  });
}

async function ensureLocalVideoFile(urlOrDataUri, filename) {
  if (!urlOrDataUri) return urlOrDataUri;
  if (urlOrDataUri.startsWith('file:')) return urlOrDataUri;
  if (urlOrDataUri.startsWith('data:')) {
    try {
      const base64 = urlOrDataUri.split(',')[1] || '';
      const path = `${FileSystem.cacheDirectory}${filename}`;
      await FileSystem.writeAsStringAsync(path, base64, { encoding: FileSystem.EncodingType.Base64 });
      return path;
    } catch (e) {
      return urlOrDataUri;
    }
  }
  // Vidéo hébergée à distance (URL https, cas normal une fois la génération
  // terminée -- voir setVideoUri(videoUrl) dans finishGeneration) : Sharing.shareAsync et
  // MediaLibrary.saveToLibraryAsync exigent tous les deux un fichier LOCAL (file://), pas une URL
  // distante -- passée telle quelle, les deux échouaient silencieusement et retombaient dans le
  // catch ("Oups, le partage/téléchargement n'a pas pu s'ouvrir", retour Tristana 20 juillet).
  // On télécharge donc d'abord la vidéo dans le cache local avant de la partager/enregistrer.
  if (urlOrDataUri.startsWith('http')) {
    try {
      const path = `${FileSystem.cacheDirectory}${filename}`;
      const result = await FileSystem.downloadAsync(urlOrDataUri, path);
      return result && result.uri ? result.uri : urlOrDataUri;
    } catch (e) {
      return urlOrDataUri;
    }
  }
  return urlOrDataUri;
}

