function SimpleSlider({ value, onValueChange, min, max, step, color }) {
  const sliderWidth = useRef(0);
  const panResponder = useRef(
    PanResponder.create({
      onStartShouldSetPanResponder: () => true,
      onMoveShouldSetPanResponder: () => true,
      onPanResponderGrant: (evt) => {
        const x = evt.nativeEvent.locationX;
        const ratio = Math.max(0, Math.min(1, x / sliderWidth.current));
        const raw = min + ratio * (max - min);
        const stepped = Math.round(raw / step) * step;
        onValueChange(Math.max(min, Math.min(max, Math.round(stepped * 100) / 100)));
      },
      onPanResponderMove: (evt) => {
        const x = evt.nativeEvent.locationX;
        const ratio = Math.max(0, Math.min(1, x / sliderWidth.current));
        const raw = min + ratio * (max - min);
        const stepped = Math.round(raw / step) * step;
        onValueChange(Math.max(min, Math.min(max, Math.round(stepped * 100) / 100)));
      },
    })
  ).current;
  const pct = ((value - min) / (max - min)) * 100;
  return (
    <View
      style={{ height: 36, justifyContent: 'center', marginVertical: 6 }}
      onLayout={(e) => { sliderWidth.current = e.nativeEvent.layout.width; }}
      {...panResponder.panHandlers}
    >
      <View style={{ height: 6, backgroundColor: '#2A2F45', borderRadius: 3 }}>
        <View style={{ width: `${pct}%`, height: '100%', backgroundColor: color || '#A78BFA', borderRadius: 3 }} />
      </View>
      <View style={{ position: 'absolute', left: `${pct}%`, width: 22, height: 22, borderRadius: 11, backgroundColor: color || '#A78BFA', marginLeft: -11, top: 7, shadowColor: '#000', shadowOpacity: 0.3, shadowRadius: 3 }} />
    </View>
  );
}


